  "type": "LEARNING_CARD",
  "lessonText": "Learn the essentials of holding your guitar for optimal playing comfort.",
  "data": {
    "learningCards": [
      {
        "title": "Positioning the Guitar",
        "content": "Rest the body of the guitar on your right leg if seated. Keep the neck angled slightly upwards.",
        "layout": "bullet"
      },
      {
        "title": "Hand Placement",
        "content": "Use your left hand to hold the neck. Your fingers should curve naturally over the fretboard.",
        "layout": "bullet"
      },
      {
        "title": "Posture",
        "content": "Sit up straight with relaxed shoulders. Keep your back straight and avoid slouching.",
        "layout": "bullet"
      },
      {
        "title": "Strumming Hand",
        "content": "Position your right hand above the sound hole. Use a relaxed wrist for strumming.",
        "layout": "bullet"
      }
    ]
  }
}
